async function seed() {
  console.log('🌱 Seeding TMFoodStuff Supabase...\n')

  // 1. Upsert categories
  console.log('📂 Upserting categories...')
  for (const cat of categories) {
    const { data: existing } = await supabase.from('categories').select('id').eq('slug', cat.slug).single()
    if (existing) {
      // Update
      await supabase.from('categories').update({ name: cat.name, name_ar: cat.name_ar, emoji: cat.emoji, description: cat.description }).eq('id', existing.id)
      console.log(`  ↩ Updated: ${cat.name}`)
    } else {
      const { error } = await supabase.from('categories').insert(cat)
      if (error) console.log(`  ❌ ${cat.name}: ${error.message}`)
      else console.log(`  ✓ Created: ${cat.name}`)
    }
  }

  // 2. Get category ID map
  const { data: cats } = await supabase.from('categories').select('id, slug')
  const catMap = {}
  for (const c of cats) catMap[c.slug] = c.id
  console.log('\nCategory map:', catMap)

  // 3. Upsert all products
  console.log(`\n📦 Upserting ${products.length} products...`)
  let created = 0, updated = 0, errors = 0

  for (const p of products) {
    const dbProduct = {
      name: p.name,
      name_ar: p.nameAr,
      slug: p.slug,
      category_id: catMap[p.categorySlug],
      description: p.description,
      price_aed: p.priceAED,
      unit: p.unit,
      stock: p.stock,
      is_organic: p.isOrganic,
      is_featured: p.isFeatured,
      origin: p.origin,
      emoji: p.emoji,
      image_url: p.imageUrl || null,
      is_active: true,
      updated_at: new Date().toISOString(),
    }

    const { data: existing } = await supabase.from('products').select('id').eq('slug', p.slug).single()

    if (existing) {
      const { error } = await supabase.from('products').update(dbProduct).eq('id', existing.id)
      if (error) { console.log(`  ❌ Update ${p.name}: ${error.message}`); errors++ }
      else updated++
    } else {
      const { error } = await supabase.from('products').insert(dbProduct)
      if (error) { console.log(`  ❌ Insert ${p.name}: ${error.message}`); errors++ }
      else created++
    }
  }

  console.log(`\n✅ Done! ${created} created, ${updated} updated, ${errors} errors`)
  console.log(`Total products in DB should now be ${products.length}`)
}

seed().catch(e => { console.error('❌ Error:', e); process.exit(1) })
